public class Codec {

    private static final String CHAR = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
    private HashMap<String, String> longToShort = new HashMap<>();
    private HashMap<String, String> shortToLong = new HashMap<>();
    private int counter = 0;

    private String toBase62(int num) {
        if (num == 0) {
            return "0";
        }
        StringBuilder sb = new StringBuilder();
        while (num > 0) {
            int rem = num % 62;
            sb.append(CHAR.charAt(rem));
            num = num / 62;
        }
        return sb.reverse().toString();
    }

    // Encodes a URL to a shortened URL.
    public String encode(String longUrl) {
        if (longToShort.containsKey(longUrl)) {
            return longToShort.get(longUrl);
        } else {
            int currentCount = counter;
            counter++;
            String shortCode = toBase62(currentCount);
            String shortUrl = "http://tinyurl.com/" + shortCode;
            longToShort.put(longUrl, shortUrl);
            shortToLong.put(shortUrl, longUrl);
            return shortUrl;
        }
    }

    // Decodes a shortened URL to its original URL.
    public String decode(String shortUrl) {
        return shortToLong.get(shortUrl);
    }
}

